// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object
  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [satisfaction, setSatisfaction] = useState<number>(0);
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');
  const [touchedName, setTouchedName] = useState<boolean>(false);
  const [touchedEmail, setTouchedEmail] = useState<boolean>(false);
  const [touchedStep2, setTouchedStep2] = useState<boolean>(false);
  const totalSteps = 5;
  const totalFormSteps = 4;
  const nameError = touchedName && !name.trim() ? 'Name is required.' : '';
  const isEmailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const emailError = touchedEmail
    ? !email.trim()
      ? 'Email is required.'
      : !isEmailValid
        ? 'Please enter a valid email address.'
        : ''
    : '';
  const satisfactionError = touchedStep2 && !(satisfaction >= 1 && satisfaction <= 5) ? 'Please select a satisfaction rating.' : '';
  const canGoNext = useMemo(() => {
    if (step === 1) {
      return name.trim().length > 0 && isEmailValid;
    }
    if (step === 2) {
      return satisfaction >= 1 && satisfaction <= 5;
    }
    if (step === 3) {
      return true;
    }
    if (step === 4) {
      return comments.length <= 500;
    }
    return true;
  }, [step, name, isEmailValid, satisfaction, comments]);
  const stepProgress = useMemo(() => (Math.min(step, totalFormSteps) / totalFormSteps) * 100, [step, totalFormSteps]);
  const handleFeatureToggle = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        if (prev.includes(feature)) return prev;
        return [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const handleNext = useCallback(() => {
    if (step === 1) {
      setTouchedName(true);
      setTouchedEmail(true);
      if (!(name.trim().length > 0 && isEmailValid)) return;
    }
    if (step === 2) {
      setTouchedStep2(true);
      if (!(satisfaction >= 1 && satisfaction <= 5)) return;
    }
    if (step < totalSteps) {
      setStep((prev) => prev + 1);
    }
  }, [step, totalSteps, name, isEmailValid, satisfaction]);

  const handleBack = useCallback(() => {
    if (step > 1) setStep((prev) => prev - 1);
  }, [step]);

  const handleSubmit = useCallback(() => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction,
      features,
      comments: comments.trim(),
    });
  }, [submit, name, email, satisfaction, features, comments]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" border shadow="sm" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={3}>Survey</Heading>
              <Badge variant="primary">Step {Math.min(step, totalFormSteps)} of {totalFormSteps}</Badge>
            </Row>
            <Progress value={stepProgress} max={100} size="md" variant="default" />
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  error={nameError}
                  placeholder="Enter your full name"
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={(value) => {
                    setEmail(value);
                    if (!touchedEmail) setTouchedEmail(true);
                  }}
                  required
                  error={emailError}
                  placeholder="Enter your email"
                />
              </Stack>
            )}
            {step === 2 && (
              <RadioGroup
                label="How satisfied are you?"
                value={satisfaction > 0 ? String(satisfaction) : ''}
                onChange={(value) => {
                  setSatisfaction(Number(value));
                  setTouchedStep2(true);
                }}
                options={(props.satisfactionLabels || []).map((label, index) => ({
                  value: String(index + 1),
                  label: `${index + 1} - ${label}`,
                }))}
                direction="vertical"
                error={satisfactionError}
              />
            )}
            {step === 3 && (
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">Select features you're interested in</Text>
                {(props.featureOptions || []).length === 0 ? (
                  <Alert variant="info">No feature options available.</Alert>
                ) : (
                  (props.featureOptions || []).map((feature) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={features.includes(feature)}
                      onChange={(checked) => handleFeatureToggle(feature, checked)}
                    />
                  ))
                )}
              </Stack>
            )}
            {step === 4 && (
              <TextArea
                label="Additional comments (optional)"
                value={comments}
                onChange={setComments}
                rows={6}
                maxLength={500}
                showCount
                helperText="Share anything else you'd like us to know."
              />
            )}
            {step === 5 && (
              <Card padding="var(--ggui-spacing-4)" border shadow="none" radius="md">
                <Stack gap="var(--ggui-spacing-3)">
                  <Heading level={5}>Review your answers</Heading>
                  <Text><Text is="span" weight="semibold">Name:</Text> {name || '—'}</Text>
                  <Text><Text is="span" weight="semibold">Email:</Text> {email.trim() || '—'}</Text>
                  <Text><Text is="span" weight="semibold">Satisfaction:</Text> {satisfaction >= 1 && satisfaction <= 5 ? satisfaction : '—'}</Text>
                  <Text><Text is="span" weight="semibold">Features:</Text> {features.length ? features.join(', ') : 'None selected'}</Text>
                  <Text><Text is="span" weight="semibold">Comments:</Text> {comments.trim() || 'No comments'}</Text>
                </Stack>
              </Card>
            )}
            <Divider margin="var(--ggui-spacing-2)" />
            <Row justify="between" align="center">
              <Button variant="secondary" onClick={handleBack} disabled={step === 1}>Back</Button>
              {step < totalSteps ? (
                <Button variant="primary" onClick={handleNext} disabled={!canGoNext}>Next</Button>
              ) : (
                <Button variant="primary" onClick={handleSubmit}>Submit</Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

