import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [tasksState, setTasksState] = useState<Array<{ id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string }>>([]);
  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');
  const [addingColumnId, setAddingColumnId] = useState<string>('');
  const [newTaskTitle, setNewTaskTitle] = useState<string>('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const processedEventKeysRef = useRef<Record<string, boolean>>({});

  const validColumnIds = useMemo(
    () => (props.columns || []).map((col) => col.id).filter((id): id is string => Boolean(id)),
    [props.columns]
  );

  const defaultTodoColumnId = useMemo(() => {
    const todoColumn = (props.columns || []).find((col) => col.id === 'todo');
    return todoColumn?.id || '';
  }, [props.columns]);

  const doneColumnId = useMemo(() => {
    const doneColumn = (props.columns || []).find((col) => (col.name || '').toLowerCase() === 'done' || col.id === 'done');
    if (doneColumn?.id) return doneColumn.id;
    return 'done';
  }, [props.columns]);

  const normalizeTask = useCallback(
    (
      task: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string },
      fallbackId: string
    ) => ({
      id: task.id || fallbackId,
      title: task.title || 'Untitled Task',
      priority: task.priority || 'medium',
      assignee: task.assignee || 'NA',
      column: task.column && validColumnIds.includes(task.column) ? task.column : defaultTodoColumnId,
      dueDate: task.dueDate,
    }),
    [defaultTodoColumnId, validColumnIds]
  );

  useEffect(() => {
    setTasksState((prev) => {
      const incoming = (props.tasks || []).map((task, index) => normalizeTask(task, `task-${index}`));
      const prevMap = new Map(prev.map((task) => [task.id, task]));
      const merged: Array<{ id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string }> = [];

      incoming.forEach((task) => {
        const existing = prevMap.get(task.id);
        if (existing) {
          merged.push({ ...existing, ...task });
          prevMap.delete(task.id);
        } else {
          merged.push(task);
        }
      });

      prevMap.forEach((task) => merged.push(task));
      return merged;
    });
  }, [props.tasks, normalizeTask]);

  useEffect(() => {
    const latest = taskChanged.latest;
    if (!latest) return;
    const incoming = latest.task;
    const incomingId = incoming?.id || '';
    if (!incomingId) return;

    const eventKey = `${latest.action || 'edit'}:${incomingId}:${incoming?.column || ''}:${incoming?.title || ''}:${incoming?.dueDate || ''}:${incoming?.priority || ''}`;
    if (processedEventKeysRef.current[eventKey]) return;
    processedEventKeysRef.current[eventKey] = true;

    setTasksState((prev) => {
      let next = prev;

      if (latest.action === 'delete') {
        return next.filter((task) => task.id !== incomingId);
      }

      const normalized = normalizeTask(incoming || {}, incomingId);
      const existingById = next.find((task) => task.id === incomingId);

      if (!existingById && latest.action === 'create') {
        const optimisticIndex = next.findIndex(
          (task) =>
            task.id.startsWith('temp-') &&
            task.title === normalized.title &&
            task.column === normalized.column &&
            task.priority === normalized.priority
        );
        if (optimisticIndex >= 0) {
          next = next.map((task, index) => (index === optimisticIndex ? { ...task, ...normalized, id: incomingId } : task));
          return next;
        }
      }

      if (!existingById) {
        return [...next, normalized];
      }

      return next.map((task) => (task.id === incomingId ? { ...task, ...normalized } : task));
    });
  }, [taskChanged.latest, normalizeTask]);

  const priorityVariant = useCallback((priority: 'low' | 'medium' | 'high') => {
    if (priority === 'high') return 'error';
    if (priority === 'medium') return 'warning';
    return 'success';
  }, []);

  const totalTasks = tasksState.length;
  const completedTasks = tasksState.filter((task) => task.column === doneColumnId).length;

  const getTasksForColumn = useCallback(
    (columnId: string) => tasksState.filter((task) => task.column === columnId),
    [tasksState]
  );

  const moveTask = useCallback(
    (taskId: string, nextColumn: string) => {
      if (!validColumnIds.includes(nextColumn)) return;
      setTasksState((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: nextColumn } : task)));
      taskUpdate({ action: 'move', taskId, data: { column: nextColumn } });
    },
    [taskUpdate, validColumnIds]
  );

  const startEditTask = useCallback((taskId: string, title: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(title);
  }, []);

  const saveEditTask = useCallback(() => {
    if (!editingTaskId) return;
    const trimmed = editingTitle.trim();
