          </Row>
        </Card>

        <Row gap="var(--ggui-spacing-4)" align="start">
          {(props.columns || []).filter((column) => Boolean(column.id)).map((column) => {
            const columnId = column.id as string;
            const columnTasks = getTasksForColumn(columnId);
            return (
              <Card key={columnId} padding="var(--ggui-spacing-4)" border shadow="sm">
                <Stack gap="var(--ggui-spacing-4)">
                  <Row justify="between" align="center">
