                              options={(props.columns || [])
                                .filter((col) => Boolean(col.id))
                                .map((col) => ({
                                  value: col.id as string,
                                  label: col.name || 'Untitled Column',
                                }))}
                            />

                            <Row gap="var(--ggui-spacing-2)">
                              {editingTaskId === task.id ? (
                                <>
                                  <Button variant="primary" size="sm" onPress={saveEditTask}>Save</Button>
                                  <Button
                                    variant="ghost"
