const CATEGORY_COLORS: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-100, #fee2e2)',
  'alkaline earth metal': 'var(--ggui-color-warning-100, #fef3c7)',
  'transition metal': 'var(--ggui-color-primary-100, #e0f2fe)',
  'post-transition metal': 'var(--ggui-color-info-100, #cffafe)',
  metalloid: 'var(--ggui-color-success-100, #dcfce7)',
  nonmetal: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
  halogen: 'var(--ggui-color-warning-200, #fde68a)',
  'noble gas': 'var(--ggui-color-primary-200, #bae6fd)',
  'noble-gas': 'var(--ggui-color-primary-200, #bae6fd)',
  lanthanide: 'var(--ggui-color-success-200, #bbf7d0)',
  actinide: 'var(--ggui-color-error-200, #fecaca)',
  unknown: 'var(--ggui-color-outlineVariant, #e4e4e7)',
};

function normalizeCategory(category?: string): string {
  return (category || 'unknown').trim().toLowerCase();
}

function getCategoryColor(category?: string): string {
  const normalized = normalizeCategory(category);
  return CATEGORY_COLORS[normalized] || 'var(--ggui-color-outlineVariant, #e4e4e7)';
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const safeElements = useMemo(() => props.elements || [], [props.elements]);

  const categories = useMemo(() => {
    const unique = new Set<string>();
    safeElements.forEach((element) => {
      unique.add(normalizeCategory(element.category));
    });
    return Array.from(unique).sort((a, b) => a.localeCompare(b));
  }, [safeElements]);

  const filteredElements = useMemo(() => {
    const q = query.trim().toLowerCase();
    if (!q) return safeElements;
    return safeElements.filter((element) => {
      const name = (element.name || '').toLowerCase();
      const symbol = (element.symbol || '').toLowerCase();
      return name.includes(q) || symbol.includes(q);
    });
  }, [safeElements, query]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber === null) return null;
    return safeElements.find((element) => element.atomicNumber === selectedAtomicNumber) || null;
  }, [safeElements, selectedAtomicNumber]);

  useEffect(() => {
    if (filteredElements.length === 0) {
      setSelectedAtomicNumber(null);
      return;
    }
    if (selectedAtomicNumber === null) return;
