export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  const [messageList, setMessageList] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages || []);
  const [draft, setDraft] = useState<string>('');
  const [typingState, setTypingState] = useState<StreamTyping | null>(null);
  const [isUserNearBottom, setIsUserNearBottom] = useState<boolean>(true);
  const scrollRef = useRef<HTMLDivElement | null>(null);
  const processedMessageCountRef = useRef<number>(0);
  const processedTypingCountRef = useRef<number>(0);
  useEffect(() => {
    setMessageList(props.messages || []);
  }, [props.messages]);

  useEffect(() => {
    const nextMessages = message.all || [];
    const startIndex = processedMessageCountRef.current;
    if (nextMessages.length > startIndex) {
      const newMessages = nextMessages.slice(startIndex);
      setMessageList((prev) => [...prev, ...newMessages]);
      processedMessageCountRef.current = nextMessages.length;
    }
  }, [message.all, message.latest]);

  useEffect(() => {
    const nextTypingEvents = typing.all || [];
    const startIndex = processedTypingCountRef.current;
    if (nextTypingEvents.length > startIndex) {
      const latestTypingEvent = nextTypingEvents[nextTypingEvents.length - 1] as StreamTyping;
      setTypingState(latestTypingEvent);
      processedTypingCountRef.current = nextTypingEvents.length;
    }
  }, [typing.all, typing.latest]);

  useEffect(() => {
    const container = scrollRef.current;
    if (!container) return;
    const onScroll = () => {
      const distanceFromBottom = container.scrollHeight - container.scrollTop - container.clientHeight;
      setIsUserNearBottom(distanceFromBottom <= 80);
    };
    onScroll();
    container.addEventListener('scroll', onScroll);
    return () => {
      container.removeEventListener('scroll', onScroll);
    };
  }, []);

  useEffect(() => {
    if (!scrollRef.current) return;
