            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {typingState.sender} is typing...
            </Text>
          ) : null}

          <Box
            padding="var(--ggui-spacing-4)"
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            borderRadius="var(--ggui-shape-radius-md, 8px)"
          >
            <Box
              padding="var(--ggui-spacing-4)"
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              borderRadius="var(--ggui-shape-radius-md, 8px)"
            >
              <Box
                ref={scrollRef as unknown as React.RefObject<HTMLDivElement>}
                style={{
                  maxHeight: '60vh',
                  overflowY: 'auto',
                  paddingRight: 'var(--ggui-spacing-1)',
                }}
              >
                <Stack gap="var(--ggui-spacing-3)">
                  {groupedMessages.length === 0 ? (
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                      No messages yet.
                    </Text>
                  ) : (
                    groupedMessages.map((group, groupIndex) => {
                      const isOwn = group.sender === props.currentUser;
                      return (
                        <Stack key={`${group.sender || 'unknown'}-${groupIndex}`} gap="var(--ggui-spacing-1)" align={isOwn ? 'end' : 'start'}>
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                            {group.sender || 'Unknown'}
                          </Text>
                          {group.items.map((item, itemIndex) => (
                            <Box
                              key={`${groupIndex}-${itemIndex}-${item.timestamp || ''}`}
                              padding="var(--ggui-spacing-2)"
                              background={isOwn ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                              borderRadius="var(--ggui-shape-radius-md, 8px)"
                            >
                              <Stack gap="var(--ggui-spacing-1)">
                                <Text
                                  variant="bodySmall"
                                  color={isOwn ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)'}
                                >
                                  {item.text || ''}
                                </Text>
                                <Text
                                  variant="caption"
                                  color={isOwn ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                                  align={isOwn ? 'right' : 'left'}
                                >
                                  {formatTimestamp(item.timestamp)}
                                </Text>
                              </Stack>
                            </Box>
                          ))}
                        </Stack>
                      );
                    })
                  )}
                </Stack>
              </Box>
            </Box>
          </Box>

          <Divider margin="var(--ggui-spacing-2)" />

          <Row gap="var(--ggui-spacing-2)" align="end">
            <Box style={{ flex: 1 }}>
