                placeholder="Write a message..."
                value={draft}
                onChange={setDraft}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') {
                    e.preventDefault();
                    handleSend();
                  }
                }}
              />
            </Box>
            <Button
              variant="primary"
