type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update
  const [stocks, setStocks] = useState<Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>>(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState<Date>(() => new Date());
  const [now, setNow] = useState<Date>(new Date());
  const [flashingSymbols, setFlashingSymbols] = useState<Record<string, boolean>>({});

  useEffect(() => {
    setStocks(props.stocks ?? []);
  }, [props.stocks]);

  useEffect(() => {
    const intervalId = setInterval(() => {
      setNow(new Date());
    }, 1000);

    return () => {
      clearInterval(intervalId);
    };
  }, []);

  useEffect(() => {
    if (!priceUpdate.latest || !priceUpdate.latest.symbol) {
      return;
    }

    const incomingSymbol = priceUpdate.latest.symbol;

    setStocks((prev) => {
      const hasMatch = prev.some((stock) => stock.symbol === incomingSymbol);
      if (!hasMatch) {
        return prev;
      }

      return prev.map((stock) => {
        if (stock.symbol !== incomingSymbol) {
          return stock;
        }

        return {
          ...stock,
          price: priceUpdate.latest?.price ?? stock.price,
          change: priceUpdate.latest?.change ?? stock.change,
          changePercent: priceUpdate.latest?.changePercent ?? stock.changePercent,
        };
      });
    });

    setLastUpdated(new Date());
    setFlashingSymbols((prev) => ({ ...prev, [incomingSymbol]: true }));

    const timeoutId = setTimeout(() => {
      setFlashingSymbols((prev) => ({ ...prev, [incomingSymbol]: false }));
    }, 600);

    return () => {
      clearTimeout(timeoutId);
    };
  }, [priceUpdate.latest]);

  const statusVariant = useMemo(() => {
    if (marketStatus.latest?.status === 'open') {
      return 'success' as const;
    }
    if (marketStatus.latest?.status === 'closed') {
      return 'error' as const;
