                </Text>
                <Badge variant={statusVariant}>
                  {statusLabel}
                </Badge>
              </Row>
            </Stack>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Live Clock: {now.toLocaleTimeString()}
            </Text>
          </Row>
        </Card>

        {!stocks || stocks.length === 0 ? (
          <Alert variant="info" title="No stocks available">
            No stock data is currently available.
          </Alert>
        ) : (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
            {stocks.map((stock, index) => {
              const isPositive = (stock.change ?? 0) >= 0;
              const accentColor = isPositive
                ? 'var(--ggui-color-success, #16a34a)'
                : 'var(--ggui-color-error, #dc2626)';
              const arrow = isPositive ? '▲' : '▼';
              const symbolKey = stock.symbol ?? `stock-${index}`;
              const isFlashing = stock.symbol ? flashingSymbols[stock.symbol] : false;

              return (
                <Card
                  key={symbolKey}
                  padding="var(--ggui-spacing-6)"
                  radius="lg"
                  shadow="sm"
                  border
                >
                  <Box
                    padding="var(--ggui-spacing-4)"
                    borderRadius="var(--ggui-shape-radius-md, 8px)"
                    background={isFlashing ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                  >
                    <Stack gap="var(--ggui-spacing-2)">
                      <Text
                        size="2xl"
                        weight="bold"
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        {stock.symbol ?? '—'}
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {stock.name ?? 'Unknown Company'}
                      </Text>
                    </Stack>
                  </Box>

                  <Spacer size={16} />

                  <Stack gap="var(--ggui-spacing-2)">
                    <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                      ${(stock.price ?? 0).toFixed(2)}
                    </Text>
                    <Text variant="body" color={accentColor}>
                      {(stock.change ?? 0) >= 0 ? '+' : ''}{(stock.change ?? 0).toFixed(2)}
                    </Text>
                    <Row gap="var(--ggui-spacing-2)" align="center">
                      <Text variant="label" color={accentColor}>
                        {arrow} {(stock.changePercent ?? 0) >= 0 ? '+' : ''}{(stock.changePercent ?? 0).toFixed(2)}%
                      </Text>
                    </Row>
                  </Stack>

                  <Box
                    margin="var(--ggui-spacing-4) 0 0 0"
