    setAvatar(props.initialProfile?.avatar ?? (avatars[0] ?? '😀'));
    setRole(props.initialProfile?.role ?? (roles[0] ?? 'Developer'));
    setEmailNotifications(props.initialProfile?.emailNotifications ?? true);
    setTheme(props.initialProfile?.theme === 'dark' ? 'dark' : 'light');
  }, [props.initialProfile, avatars, roles]);

  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const step1Valid = name.trim().length > 0 && emailValid && avatar.trim().length > 0;
  const step2Valid = role.trim().length > 0 && (theme === 'light' || theme === 'dark');
  const canGoNext = (step === 1 && step1Valid) || (step === 2 && step2Valid);
  const progressValue = (step / 3) * 100;

  const handleNext = useCallback(() => {
    if (step < 3 && canGoNext) {
      setStep((prev) => prev + 1);
    }
  }, [step, canGoNext]);

  const handleBack = useCallback(() => {
    if (step > 1) {
      setStep((prev) => prev - 1);
    }
  }, [step]);

  const handleComplete = useCallback(() => {
    if (!step1Valid || !step2Valid) {
      return;
    }
    setSubmitted(true);
    complete({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  }, [step1Valid, step2Valid, complete, name, email, avatar, role, emailNotifications, theme]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="sm" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={3}>Onboarding Wizard</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Complete your profile setup in three quick steps.
            </Text>
          </Stack>
        </Card>

        <Card
          padding="var(--ggui-spacing-6)"
          shadow="md"
          radius="lg"
        >
          <Box
            style={{
              animation: 'ggui-fadeIn 200ms ease-out',
              transition: 'all 200ms ease-in-out',
            }}
          >
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Profile Setup</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  placeholder="Enter your name"
                  required
                  error={!name.trim() ? 'Name is required.' : undefined}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  placeholder="you@example.com"
                  required
                  error={email.length > 0 && !emailValid ? 'Please enter a valid email address.' : undefined}
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Avatar
                  </Text>
                  <Row gap="var(--ggui-spacing-2)" wrap>
                    {avatars.map((item) => (
                      <Card
                        key={item}
                        as={Clickable}
                        onClick={() => setAvatar(item)}
                        padding="var(--ggui-spacing-2)"
                        radius="md"
                        border
                        shadow="none"
                      >
                        <Box
                          background={avatar === item ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'var(--ggui-color-surface, #fafafa)'}
                          borderRadius="var(--ggui-shape-radius-md, 8px)"
                          padding="var(--ggui-spacing-2)"
                        >
                          <Text size="2xl" align="center">{item}</Text>
                        </Box>
                      </Card>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  options={roles.map((option) => ({ value: option, label: option }))}
                  placeholder="Select your role"
                  required
                />
                <Toggle
                  label="Email Notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Toggle
                  label="Theme Preference (Dark mode)"
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Current theme: {theme}
                </Text>
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review &amp; Confirm</Heading>
                <Card padding="var(--ggui-spacing-4)" shadow="none" radius="md">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row align="center" gap="var(--ggui-spacing-2)">
                      <Text variant="label">Avatar:</Text>
                      <Text>{avatar}</Text>
                    </Row>
                    <Text><Text is="span" variant="label">Name:</Text> {name || '-'}</Text>
                    <Text><Text is="span" variant="label">Email:</Text> {email || '-'}</Text>
                    <Text><Text is="span" variant="label">Role:</Text> {role || '-'}</Text>
                    <Text><Text is="span" variant="label">Email Notifications:</Text> {emailNotifications ? 'On' : 'Off'}</Text>
                    <Text><Text is="span" variant="label">Theme:</Text> {theme}</Text>
                  </Stack>
                </Card>
                {submitted && (
                  <Alert variant="success" title="Setup complete">
                    Your onboarding data has been submitted.
                  </Alert>
                )}
              </Stack>
            )}
          </Box>
        </Card>

        <Row justify="between" align="center">
          <Button variant="ghost" onClick={handleBack} disabled={step === 1}>
            Back
          </Button>
          {step < 3 ? (
            <Button variant="primary" onClick={handleNext} disabled={!canGoNext}>
              Next
            </Button>
          ) : (
            <Row gap="var(--ggui-spacing-2)">
              <Button variant="secondary" onClick={handleBack}>
                Go Back
              </Button>
              <Button variant="primary" onClick={handleComplete} disabled={!step1Valid || !step2Valid}>
                Complete Setup
              </Button>
            </Row>
          )}
        </Row>
      </Stack>
    </Container>

  );
}
